    def __init__(self):
        super().__init__()
        self.session_memory = {}

    def forward(self, session_id, **kwargs):
        # Store memory snapshot
        current_memory = kwargs.get('memory', {})
        prev_memory = self.session_memory.get(session_id, {})

        # Check for unexpected memory mutations
        if prev_memory:
            deleted_keys = set(prev_memory) - set(current_memory)
            if deleted_keys:
                print(f'⚠️  Memory loss in session {session_id}: {deleted_keys}')

        self.session_memory[session_id] = current_memory.copy()
        return kwargs

