import dspy
import json
from typing import Dict, Any

class PersistentMemoryModule(dspy.Module):
    def __init__(self, base_module, memory_store):
        super().__init__()
        self.base_module = base_module
        self.memory_store = memory_store

    def forward(self, session_id: str, query: str, **kwargs):
        # Always inject complete memory context
        memory_context = self.memory_store.get(session_id, {})

        enriched_kwargs = {
            **kwargs,
            'memory': memory_context,
            'session_id': session_id,
            'query': query
        }

        result = self.base_module(**enriched_kwargs)

        # Persist any memory updates
        if 'memory_updates' in result:
            self.memory_store[session_id] = {
                **memory_context,
                **result['memory_updates']
            }

        return result

