import dspy
import vex

from typing import Dict, Any

# Complete Vex+DSPy memory agent
@vex.integration('dspy-memory-agent')
class MemoryManagedAgent(dspy.Module):
    def __init__(self):
        super().__init__()
        self.select_memory = dspy.ChainOfThought('available_memory, query -> selected_context')
        self.reason = dspy.ChainOfThought('context, query, memory_summary -> answer')
        self.memory_store: Dict[str, Dict] = {}

    @vex.verify(
        timeout=30,
        assertions={
            'memory_persistence': 'memory_store[session_id] is not empty',
            'context_utilization': lambda res: len(res['used_context']) / len(res['available_memory']) > 0.1,
            'no_context_drift': lambda res: verify_memory_consistency(res)
        },
        remediation={'add_memory_wrapper': 'Wrap with PersistentMemoryModule'}
    )
    def forward(self, session_id: str, query: str, **kwargs) -> Dict[str, Any]:
        # Load persistent memory
        available_memory = self.memory_store.get(session_id, {})

        # Vex-protected memory selection
        selection = self.select_memory(
            available_memory=str(available_memory),
            query=query
        )

        result = self.reason(
            context=selection.selected_context,
            query=query,
            memory_summary=f"Session: {session_id}, Items: {len(available_memory)}"
        )

        # Persist updates
        self.memory_store.setdefault(session_id, {}).update({
            'last_query': query,
            'last_answer': result.answer
        })

        return {
            'answer': result.answer,
            'used_context': selection.selected_context,
            'available_memory': list(available_memory.keys()),
            'session_id': session_id
        }

# Usage
agent = MemoryManagedAgent()
result = agent(session_id='user123', query='What was discussed previously?')
